// hooks and interceptors per client, for fast access.
type (
	hooks struct {
		BacktestKlineAnalysis, BacktestResult, BacktestTask, Strategy []ent.Hook
	}
	inters struct {
		BacktestKlineAnalysis, BacktestResult, BacktestTask, Strategy []ent.Interceptor
	}
)
